mapper.select:
SELECT 
    s.id, s.standard_name, s.org_id, s.dept_id, s.position_id, s.grade_level,
    s.base_salary, s.performance_salary, s.position_allowance, s.meal_allowance,
    s.transport_allowance, s.communication_allowance, s.housing_allowance, s.other_allowance,
    s.status, s.industry_type, s.ext_json, s.remark, s.created_time, s.updated_time,
    o.name as orgName, d.name as deptName, p.name as positionName
FROM hr_payroll_standard s
LEFT JOIN hr_organization o ON s.org_id = o.id
LEFT JOIN hr_department d ON s.dept_id = d.id
LEFT JOIN hr_position p ON s.position_id = p.id
WHERE s.deleted = 0

    AND s.standard_name LIKE CONCAT('%', #{query.standardName}, '%')


    AND s.org_id = #{query.orgId}


    AND s.dept_id = #{query.deptId}


    AND s.position_id = #{query.positionId}


    AND s.grade_level = #{query.gradeLevel}


    AND s.status = #{query.status}


    AND s.industry_type = #{query.industryType}

ORDER BY s.created_time DESC
